local UIFriend = class("UIFriend", IGUILayout)
UIFriend.ClickType =
{
    MY_FRIEND = 1,
    FRIEND_APPLY = 2,
    NEAR_PLAYERS = 3,
    TOGETHER_BUILD = 4,
    BUILD_APPLY = 5
}


function UIFriend:onLoad()
    self:onLoadInitUI()
end

function UIFriend:onLoadInitUI()
    HostApi.log("onLoadInitUI")
    self.curTabIndex = 1
    self.closeBtn = self:getChildWindow("SkyBlockFriend-Close", GUIType.Button)
    self.closeBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onClickClose()
    end)

    self.friendLayout = self:getChildWindow("SkyBlockFriend-View", GUIType.Layout)
    self.friendGridView = IGUIListView.new("sky_block-friend-view", self.friendLayout)
    -- self.friendGridView:setConfig(0, 7, 1)

    self.builtLayout = self:getChildWindow("SkyBlockFriend-Built", GUIType.Layout)
    self.builtGridView = IGUIListView.new("sky_block-built-view", self.builtLayout)
    -- self.builtGridView:setConfig(0, 7, 1)
    self.builtBtn = self:getChildWindow("SkyBlockFriend-Built-Btn", GUIType.Button)
    self.builtBtn:SetText(Lang:getString("input_our_island"))
    self.builtBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onClickInPutOurIsland()
    end)
    self.hintIcon = self:getChildWindow("SkyBlockFriend-Hint-Icon", GUIType.StaticImage)
    self.hintText = self:getChildWindow("SkyBlockFriend-Hint-Text", GUIType.StaticText)
    self.hintText:SetText(Lang:getString("SkyBlockFriend_Built_Hint"))
    self.friend_red = self:getChildWindow("SkyBlockFriend-Red-Dot", GUIType.StaticImage)
    self.built_red = self:getChildWindow("SkyBlockFriend-Red-Dot_1", GUIType.StaticImage)

    self.myFriendBtn = self:getChildWindow("SkyBlockFriend-Table_1", GUIType.RadioButton)
    self.nearPlayersBtn = self:getChildWindow("SkyBlockFriend-Table_3", GUIType.RadioButton)
    for i = 1, 5 do
        local radioBtn = self:getChildWindow("SkyBlockFriend-Table_"..tostring(i), GUIType.RadioButton)
        radioBtn:SetText(Lang:getString("Friend_Tab_Name_"..tostring(i)))
        radioBtn:registerEvent(GUIEvent.RadioStateChanged, function()
            self:onRadioStateChanged(radioBtn, i)
        end)
        if i == 1 then
            radioBtn:SetSelected(true)
        end
    end


    self:registerDataCallBack("MultiBuildGroupData", function(data)
        self:onMultiBuildGroupData(data)
    end, JsonBuilderProcessor)

    self:registerDataCallBack("MultiBuildUpdate", function(data)
        self:onMultiBuildUpdate(data)
    end, JsonBuilderProcessor)
    self:updateSetRedPoint()
    MultiBuildData:getAllNeedList(true)
end

function UIFriend:onRadioStateChanged(radioBtn, index)
    radioBtn:SetWidth({1, 0})
    if radioBtn:IsSelected() then
        radioBtn:SetWidth({1.1, 0})
        self.curTabIndex = index
        self:updateCurGridView()
    end
end

function UIFriend:updateCurGridView()
    print("UIFriend updateCurGridView curTabIndex == "..self.curTabIndex)
    self.friendGridView:clearItems()
    self.builtGridView:clearItems()

    self.builtBtn:SetVisible(not MultiBuildData:checkMeIsIslandMaster())

    if self.curTabIndex ~= UIFriend.ClickType.TOGETHER_BUILD then
        self.friendLayout:SetVisible(true)
        self.builtLayout:SetVisible(false)
    else
        self.friendLayout:SetVisible(false)
        self.builtLayout:SetVisible(true)
    end

    if self.curTabIndex == UIFriend.ClickType.MY_FRIEND then
        self:onUpdateUserFriend(MultiBuildData.MyFriendData)
        return
    end
    if self.curTabIndex == UIFriend.ClickType.FRIEND_APPLY then
        if (self.friend_red:IsVisible()) then
            self.friend_red:SetVisible(false)
            self:checkHaveRedPoint()
        end

        self:onUpdateUserFriendApply(MultiBuildData.FriendApplyData)
        return
    end
    if self.curTabIndex == UIFriend.ClickType.NEAR_PLAYERS then
        self:onUpdateUserNearFriend(MultiBuildData.NearPlayerData)
        return
    end
    if self.curTabIndex == UIFriend.ClickType.TOGETHER_BUILD then
        self:onUpdateUserFriendBuilt(MultiBuildData.TogetherBuildData)
        return
    end
    if self.curTabIndex == UIFriend.ClickType.BUILD_APPLY then
        if (self.built_red:IsVisible()) then
            self.built_red:SetVisible(false)
            self:checkHaveRedPoint()
        end

        self:onUpdateUserBuildApply(MultiBuildData.BuildApplyData)
        return
    end
end

function UIFriend:onUpdateUserFriend(Data)
    if #Data < 0 then
        return
    end
    local curData = self:getSortData(Data)

    for i, data in pairs(curData) do
        local curItem = UIFriendItem.new("SkyBlockFriendItem.json")
        curItem.root:SetArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 0, 93 })
        curItem:setItemData(data)
        self.friendGridView:addItem(curItem)
    end
end

function UIFriend:onUpdateUserFriendApply(Data)
    if #Data < 0 then
        return
    end

    for i, data in pairs(Data) do
        local curItem = UIFriendApplyItem.new("SkyBlockFriendApplyItem.json")
        curItem.root:SetArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 0, 93 })
        curItem:setItemData(data)
        self.friendGridView:addItem(curItem)
    end
end

function UIFriend:onUpdateUserNearFriend(curData)
    if #curData < 0 then
        return
    end
    self.friendGridView:clearItems()
    local Data = self:deleteFriendData(curData)
    for i, data in pairs(Data) do
        local curItem = UINearFriendItem.new("SkyBlockNearFriendItem.json")
        curItem.root:SetArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 0, 93 })
        curItem:setItemData(data)
        self.friendGridView:addItem(curItem)
    end
end

function UIFriend:onUpdateUserFriendBuilt(curData)
    if #curData < 0 then
        return
    end

    for i = 1, 3  do
        local curItem = UIFriendBuiltItem.new("SkyBlockFriendBuiltItem.json")
        curItem.root:SetArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 0, 93 })
        curItem:setItemData(i)
        self.builtGridView:addItem(curItem)
    end
end

function UIFriend:onUpdateUserBuildApply(curData)
    if #curData < 0 then
        return
    end

    for i, data in pairs(curData) do
        local curItem = UIFriendBuildApplyItem.new("SkyBlockFriendBuildApplyItem.json")
        curItem.root:SetArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 0, 93 })
        curItem:setItemData(data)
        self.friendGridView:addItem(curItem)
    end
end

function UIFriend:getFriendInvitation()
    GUIFriendInvitation:show()
    GUIFriendInvitation:onUpdateUserFriendInvitation()
end

function UIFriend:getSortData(data)
    local sortData = {}
    for i, v in pairs(data) do
        table.insert(sortData, v)
    end

    table.sort(sortData, function ( a, b )
        if a.onLineStatus == b.onLineStatus then
            return a.isPlayCurGame > b.isPlayCurGame
        else
            return a.onLineStatus > b.onLineStatus
        end
    end)
    return sortData
end

