function UIFriend:deleteFriendData(data)
    local deleteData = {}
    for i, v in pairs(data) do
        if not MultiBuildData:checkIsMyFriend(v.userId) and tostring(GameData.userId) ~= tostring(v.userId) then
            table.insert(deleteData, v)
        else
            MultiBuildData:RemoveNearFriend(v.userId)
        end
    end
    return deleteData
end


function UIFriend:onMultiBuildGroupData(data)
    if data then
        MultiBuildData:UpdateTogetherBuildData(data)
    end
end

function UIFriend:isMainLayout()
    return false
end

function UIFriend:onClickClose()
    self:hide()
end

function UIFriend:onClickInPutOurIsland()
    print("onClickInPutOurIsland")
    local master = MultiBuildData:getBuildMaster()
    if master then
        PacketSender:sendCallOnManor(tostring(master.masterId), 3, true, 0)
    end
end

function UIFriend:onMultiBuildUpdate(data)
    print("onMultiBuildUpdate")
    if data then
        MultiBuildData:UpdateMulyiBuildData(data)
    end
end

function UIFriend:updateSetRedPoint()
    print("updateSetRedPoint ggg== "..#MultiBuildData.FriendApplyData.."   ppp == "..#MultiBuildData.BuildApplyData)
    self.friend_red:SetVisible(#MultiBuildData.FriendApplyData > 0)
    self.built_red:SetVisible(#MultiBuildData.BuildApplyData > 0)
    self:checkHaveRedPoint()
end

function UIFriend:refreshFrientApplyRed()
    self.friend_red:SetVisible(#MultiBuildData.FriendApplyData > 0)
    self:checkHaveRedPoint()
end

function UIFriend:refreshBuildApplyRed()
    self.built_red:SetVisible(#MultiBuildData.BuildApplyData > 0)
    self:checkHaveRedPoint()
end

function UIFriend:checkHaveRedPoint()

    print("checkHaveRedPoint")
    if self.friend_red:IsVisible() or self.built_red:IsVisible() then
        GUIToolBar:SetFriendRedPoint(true)
    else
         GUIToolBar:SetFriendRedPoint(false)
    end
end

